CREATE TABLE IF NOT EXISTS COMPANIES (ID INT AUTO_INCREMENT PRIMARY KEY, CREATED_AT TIMESTAMP(9) NOT NULL, UPDATED_AT TIMESTAMP(9) NULL, DELETED_AT TIMESTAMP(9) NULL, LABEL VARCHAR(255) NOT NULL, LOCATION GEOMETRY(POINT, 4326) NOT NULL);
CREATE TABLE IF NOT EXISTS EQUIPMENT_STORAGES (ID INT AUTO_INCREMENT PRIMARY KEY, CREATED_AT TIMESTAMP(9) NOT NULL, UPDATED_AT TIMESTAMP(9) NULL, DELETED_AT TIMESTAMP(9) NULL, LABEL VARCHAR(255) NOT NULL, LOCATION GEOMETRY(POINT, 4326) NOT NULL);
CREATE TABLE IF NOT EXISTS WAREHOUSES (ID INT AUTO_INCREMENT PRIMARY KEY, CREATED_AT TIMESTAMP(9) NOT NULL, UPDATED_AT TIMESTAMP(9) NULL, DELETED_AT TIMESTAMP(9) NULL, LABEL VARCHAR(255) NOT NULL, LOCATION GEOMETRY(POINT, 4326) NOT NULL, COMPANY_ID INT NOT NULL, CONSTRAINT FK_WAREHOUSES_COMPANY_ID__ID FOREIGN KEY (COMPANY_ID) REFERENCES COMPANIES(ID) ON DELETE RESTRICT ON UPDATE RESTRICT);
CREATE TABLE IF NOT EXISTS EQUIPMENT (ID INT AUTO_INCREMENT PRIMARY KEY, CREATED_AT TIMESTAMP(9) NOT NULL, UPDATED_AT TIMESTAMP(9) NULL, DELETED_AT TIMESTAMP(9) NULL, LABEL VARCHAR(255) NOT NULL, LOCATION GEOMETRY(POINT, 4326) NOT NULL, WAREHOUSE_ID INT NOT NULL, STORAGE_ID INT NULL, CONSTRAINT FK_EQUIPMENT_WAREHOUSE_ID__ID FOREIGN KEY (WAREHOUSE_ID) REFERENCES WAREHOUSES(ID) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT FK_EQUIPMENT_STORAGE_ID__ID FOREIGN KEY (STORAGE_ID) REFERENCES EQUIPMENT_STORAGES(ID) ON DELETE RESTRICT ON UPDATE RESTRICT);
CREATE TABLE IF NOT EXISTS EVENTS (ID INT AUTO_INCREMENT PRIMARY KEY, CREATED_AT TIMESTAMP(9) NOT NULL, UPDATED_AT TIMESTAMP(9) NULL, DELETED_AT TIMESTAMP(9) NULL, LABEL VARCHAR(255) NOT NULL, LOCATION GEOMETRY(POINT, 4326) NOT NULL);
CREATE TABLE IF NOT EXISTS USERS (ID INT AUTO_INCREMENT PRIMARY KEY, CREATED_AT TIMESTAMP(9) NOT NULL, UPDATED_AT TIMESTAMP(9) NULL, DELETED_AT TIMESTAMP(9) NULL, EMAIL VARCHAR(255) NOT NULL, PASSWORD VARCHAR(255) NOT NULL, "role" VARCHAR(20) NOT NULL, PHONE VARCHAR(20) NOT NULL, FIRST_NAME VARCHAR(255) NOT NULL, LAST_NAME VARCHAR(255) NOT NULL, COMPANY_ID INT NOT NULL, CONSTRAINT FK_USERS_COMPANY_ID__ID FOREIGN KEY (COMPANY_ID) REFERENCES COMPANIES(ID) ON DELETE RESTRICT ON UPDATE RESTRICT);
ALTER TABLE USERS ADD CONSTRAINT USERS_EMAIL_UNIQUE UNIQUE (EMAIL);
CREATE TABLE IF NOT EXISTS TECHNICAL_LOG_ENTRIES (ID INT AUTO_INCREMENT PRIMARY KEY, CREATED_AT TIMESTAMP(9) NOT NULL, UPDATED_AT TIMESTAMP(9) NULL, DELETED_AT TIMESTAMP(9) NULL, IS_CHECK_IN BOOLEAN NOT NULL, EQUIPMENT_ID INT NOT NULL, USER_ID INT NOT NULL, LOGGABLE INT NOT NULL, CONSTRAINT FK_TECHNICAL_LOG_ENTRIES_EQUIPMENT_ID__ID FOREIGN KEY (EQUIPMENT_ID) REFERENCES EQUIPMENT(ID) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT FK_TECHNICAL_LOG_ENTRIES_USER_ID__ID FOREIGN KEY (USER_ID) REFERENCES USERS(ID) ON DELETE RESTRICT ON UPDATE RESTRICT);
